import type { ReactNode } from 'react'
import { AnimatePresence, motion } from 'framer-motion'
import { useReducedMotionSafe } from '../hooks/useReducedMotionSafe'
import { cn } from '../utils/cn'

export { AccordionToggleIcon } from './AccordionToggleIcon'

/** Shared focus ring on accordion / disclosure triggers (matches existing sections). */
export const accordionTriggerFocusClass =
  'transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-500/80'

export type AccordionMotionPanelProps = {
  open: boolean
  panelId: string
  children: ReactNode
  className?: string
  motionKey?: string
}

/**
 * Height animation wrapper for disclosure panels (Framer Motion).
 * Parent should control `open` and supply stable `panelId` for `aria-controls`.
 */
export function AccordionMotionPanel({
  open,
  panelId,
  children,
  className,
  motionKey = panelId,
}: AccordionMotionPanelProps) {
  const reducedMotion = useReducedMotionSafe()

  return (
    <AnimatePresence initial={false}>
      {open ? (
        <motion.div
          id={panelId}
          key={motionKey}
          initial={{ height: 0, opacity: 0 }}
          animate={{ height: 'auto', opacity: 1 }}
          exit={{ height: 0, opacity: 0 }}
          transition={{
            duration: reducedMotion ? 0.12 : 0.22,
            ease: 'easeOut',
          }}
          className={cn('overflow-hidden', className)}
        >
          {children}
        </motion.div>
      ) : null}
    </AnimatePresence>
  )
}
