import { useEffect, type ReactNode } from 'react'
import { AnimatePresence, motion } from 'framer-motion'
import { useReducedMotionSafe } from '../hooks/useReducedMotionSafe'
import { Button } from './Button'
import { cn } from '../utils/cn'

export type ModalSize = 'md' | 'xl'

const panelMaxClass: Record<ModalSize, string> = {
  md: 'max-w-lg',
  xl: 'max-w-4xl',
}

export type ModalProps = {
  open: boolean
  onClose: () => void
  titleId: string
  title: ReactNode
  children: ReactNode
  size?: ModalSize
  closeLabel?: string
  /** Extra classes on the white panel (e.g. overflow) */
  panelClassName?: string
  /** Extra classes on the scrollable body below the header */
  bodyClassName?: string
}

export function Modal({
  open,
  onClose,
  titleId,
  title,
  children,
  size = 'xl',
  closeLabel = 'Close',
  panelClassName,
  bodyClassName,
}: ModalProps) {
  const reducedMotion = useReducedMotionSafe()

  useEffect(() => {
    if (typeof document === 'undefined' || !open) {
      return
    }

    const previousBodyOverflow = document.body.style.overflow
    document.body.style.overflow = 'hidden'

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        onClose()
      }
    }

    window.addEventListener('keydown', handleKeyDown)

    return () => {
      document.body.style.overflow = previousBodyOverflow
      window.removeEventListener('keydown', handleKeyDown)
    }
  }, [open, onClose])

  return (
    <AnimatePresence>
      {open ? (
        <motion.div
          className="fixed inset-0 z-[100] flex items-center justify-center px-4 py-6"
          style={{ backgroundColor: 'var(--overlay-backdrop)' }}
          role="dialog"
          aria-modal="true"
          aria-labelledby={titleId}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: reducedMotion ? 0.1 : 0.2, ease: 'easeOut' }}
          onClick={onClose}
        >
          <motion.div
            className={cn(
              'w-full overflow-hidden rounded-xl bg-white shadow-modal-panel',
              panelMaxClass[size],
              panelClassName,
            )}
            initial={reducedMotion ? { opacity: 0 } : { opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            exit={reducedMotion ? { opacity: 0 } : { opacity: 0, y: 10 }}
            transition={{ duration: reducedMotion ? 0.1 : 0.2, ease: 'easeOut' }}
            onClick={(event) => event.stopPropagation()}
          >
            <div className="flex items-start justify-between border-b border-lightGrey px-4 py-3 md:px-6 md:py-4">
              <h3 id={titleId} className="m-0 pr-4 font-heading text-brand-h3 text-foreground">
                {title}
              </h3>
              <Button type="button" variant="ghost" onClick={onClose}>
                {closeLabel}
              </Button>
            </div>
            <div className={cn('px-4 pb-4 pt-4 md:px-6 md:pb-6', bodyClassName)}>{children}</div>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  )
}
