import type { HTMLAttributes } from 'react'
import { cn } from '../utils/cn'

export type SectionShellWidth = 'narrow' | 'default' | 'wide'

const maxWidthClass: Record<SectionShellWidth, string> = {
  narrow: 'max-w-container-narrow',
  default: 'max-w-container-default',
  wide: 'max-w-container-wide',
}

export type SectionShellProps = HTMLAttributes<HTMLDivElement> & {
  width: SectionShellWidth
}

export function SectionShell({ width, className, children, ...props }: SectionShellProps) {
  return (
    <div className={cn(maxWidthClass[width], 'mx-auto px-6 lg:px-12', className)} {...props}>
      {children}
    </div>
  )
}
